import MainController.State.StatusBoardStore

def _dataset_value(dataset, row_index, column_index):
	try:
		return dataset.getValueAt(row_index, column_index)
	except Exception:
		return None

def _normalize(value):
	if value is None:
		return ""
	text = str(value).strip()
	if not text or text.lower() == "null":
		return ""
	return text

def _lookup_dataset(dataset, lookup_value, lookup_column, result_column, default_value=""):
	if dataset is None:
		return default_value
	try:
		row_count = dataset.getRowCount()
	except Exception:
		return default_value
	lookup_text = _normalize(lookup_value)
	for row_index in range(row_count):
		candidate = _normalize(_dataset_value(dataset, row_index, lookup_column))
		if lookup_text == candidate:
			return _normalize(_dataset_value(dataset, row_index, result_column)) or default_value
	return default_value

cards = MainController.State.StatusBoardStore.robotCards()
workflowConfig = self.view.custom.workflowConfig
notReadyReasonLookup = self.view.custom.notReadyReasonLookup
for card in list(cards or []):
	active_workflow = card.get("activeWorkflowNumber")
	not_ready_reason = _normalize(card.get("notReadyReason"))
	resolved_mission_type = _lookup_dataset(workflowConfig, active_workflow, 0, 4, "") if active_workflow else ""
	resolved_not_ready_reason = _lookup_dataset(notReadyReasonLookup, not_ready_reason, 0, 1, not_ready_reason) if not_ready_reason else ""
	card["workflowConfig"] = workflowConfig
	card["notReadyReasonLookup"] = notReadyReasonLookup
	card["resolvedMissionType"] = resolved_mission_type
	card["resolvedNotReadyReason"] = resolved_not_ready_reason
return cards

def _rowseq(path):
	return system.tag.browse(path).getResults()

def _rowseq_val(row, key, default=None):
	if isinstance(row, dict):
		return row.get(key, default)
	getter = getattr(row, "get", None)
	if getter is not None:
		try:
			return getter(key)
		except Exception:
			pass
	return getattr(row, key, default)

def _is_udt(row):
	tag_type = str(_rowseq_val(row, "tagType", "") or "").lower()
	return "udtinstance" in tag_type

def _fullpath(row):
	return str(_rowseq_val(row, "fullPath", "") or "")

place_rows = [row for row in _rowseq("[Otto_FleetManager]Fleet/Places") if _is_udt(row)]
robot_rows = [row for row in _rowseq("[Otto_FleetManager]Fleet/Robots") if _is_udt(row)]
container_rows = [row for row in _rowseq("[Otto_FleetManager]Fleet/Containers") if _is_udt(row)]

place_reads = []
for row in place_rows:
	path = _fullpath(row)
	place_reads.extend([path + "/ID", path + "/Name"])
place_values = system.tag.readBlocking(place_reads) if place_reads else []
place_by_id = {}
for index, row in enumerate(place_rows):
	offset = index * 2
	place_id = str(place_values[offset].value or "") if offset < len(place_values) and place_values[offset].quality.isGood() else ""
	place_name = str(place_values[offset + 1].value or "") if offset + 1 < len(place_values) and place_values[offset + 1].quality.isGood() else ""
	if place_id:
		place_by_id[place_id] = place_name or place_id

robot_reads = []
for row in robot_rows:
	path = _fullpath(row)
	robot_reads.append(path + "/ID")
robot_values = system.tag.readBlocking(robot_reads) if robot_reads else []
robot_by_id = {}
for index, row in enumerate(robot_rows):
	robot_id = str(robot_values[index].value or "") if index < len(robot_values) and robot_values[index].quality.isGood() else ""
	robot_name = str(_rowseq_val(row, "name", "") or "")
	if robot_id:
		robot_by_id[robot_id] = robot_name or robot_id

container_reads = []
for row in container_rows:
	path = _fullpath(row)
	container_reads.extend([
		path + "/ID",
		path + "/ContainerType",
		path + "/State",
		path + "/Place",
		path + "/Robot",
	])
container_values = system.tag.readBlocking(container_reads) if container_reads else []

instances = []
for index, row in enumerate(container_rows):
	offset = index * 5
	container_id = str(container_values[offset].value or "") if offset < len(container_values) and container_values[offset].quality.isGood() else ""
	container_type = str(container_values[offset + 1].value or "") if offset + 1 < len(container_values) and container_values[offset + 1].quality.isGood() else ""
	state = str(container_values[offset + 2].value or "") if offset + 2 < len(container_values) and container_values[offset + 2].quality.isGood() else ""
	place_id = str(container_values[offset + 3].value or "") if offset + 3 < len(container_values) and container_values[offset + 3].quality.isGood() else ""
	robot_id = str(container_values[offset + 4].value or "") if offset + 4 < len(container_values) and container_values[offset + 4].quality.isGood() else ""

	if place_id and place_id in place_by_id:
		location_label = "Place: {}".format(place_by_id[place_id])
	elif place_id:
		location_label = "Place: {}".format(place_id)
	elif robot_id and robot_id in robot_by_id:
		location_label = "Robot: {}".format(robot_by_id[robot_id])
	elif robot_id:
		location_label = "Robot: {}".format(robot_id)
	else:
		location_label = "Location: Unassigned"

	instances.append({
		"containerId": container_id,
		"containerType": container_type,
		"state": state,
		"locationLabel": location_label,
		"viewOnly": True,
	})

instances.sort(key=lambda row: (str(row.get("containerType") or ""), str(row.get("containerId") or "")))
return instances
